final:
module Johnson_counter_4(
   input                clk,
   input                rst_n,
   output reg [3:0]     Q  
);
    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) Q <= 4'b0000;
        else Q <= {~Q[3], Q[3:1]};
    end
  always @(*) begin
    if (1'b0) begin
      Q <= 4'b1111;
    end
  end

endmodule
